(() => {
  'use strict';
  if (window.__pcbw_uiBuilderInit) return;
  window.__pcbw_uiBuilderInit = true;

  const NS = '__pcbw_uiBuilder';
  const PANEL_ID = '__pcbw_uiBuilder_panel';

  function ensureState() {
    if (!oc.thread.customData) oc.thread.customData = {};
    if (!oc.thread.customData[NS]) {
      oc.thread.customData[NS] = {
        projectName: '',
        projectType: '',
        features: [],
        currentStep: 'idle',
        history: [],
        panelVisible: false
      };
    }
    return oc.thread.customData[NS];
  }

  function getOrCreatePanel() {
    let panel = document.getElementById(PANEL_ID);
    if (panel) return panel;

    panel = document.createElement('div');
    panel.id = PANEL_ID;
    panel.style.cssText = [
      'position: fixed',
      'top: 60px',
      'right: 16px',
      'width: 280px',
      'max-height: 420px',
      'overflow-y: auto',
      'background: light-dark(#fafbfd, #1a1d24)',
      'border: 1px solid light-dark(rgba(100,140,200,0.35), rgba(80,120,180,0.3))',
      'border-radius: 12px',
      'padding: 16px',
      'box-shadow: 0 4px 20px rgba(0,0,0,0.15)',
      'z-index: 99999',
      'font-family: system-ui, sans-serif',
      'font-size: 13px',
      'color: light-dark(#2a2e35, #d8dce6)',
      'display: none',
      'transition: opacity 0.2s ease'
    ].join('; ');

    document.body.appendChild(panel);
    return panel;
  }

  function renderPanel() {
    const state = ensureState();
    const panel = getOrCreatePanel();

    const stepLabels = {
      'idle': '⏳ Waiting for project',
      'naming': '✏️ Naming project',
      'typing': '📦 Selecting type',
      'features': '🔧 Adding features',
      'review': '✅ Review & confirm',
      'complete': '🎉 Project defined'
    };

    let html = '<div style="margin-bottom:10px;display:flex;justify-content:space-between;align-items:center;">';
    html += '<strong style="font-size:14px;">🏗️ Project Builder</strong>';
    html += '<button id="' + PANEL_ID + '_close" style="background:none;border:none;cursor:pointer;font-size:16px;color:light-dark(#666,#aaa);padding:2px 6px;">✕</button>';
    html += '</div>';
    html += '<hr style="border:none;border-top:1px solid light-dark(rgba(0,0,0,0.1),rgba(255,255,255,0.1));margin:8px 0;">';

    html += '<div style="margin-bottom:8px;"><strong>Step:</strong> ' + (stepLabels[state.currentStep] || state.currentStep) + '</div>';

    if (state.projectName) {
      html += '<div style="margin-bottom:4px;"><strong>Project:</strong> ' + escapeHtml(state.projectName) + '</div>';
    }
    if (state.projectType) {
      html += '<div style="margin-bottom:4px;"><strong>Type:</strong> ' + escapeHtml(state.projectType) + '</div>';
    }
    if (state.features.length > 0) {
      html += '<div style="margin-bottom:4px;"><strong>Features:</strong></div><ul style="margin:2px 0 6px 16px;padding:0;">';
      state.features.forEach(function(f) {
        html += '<li style="margin-bottom:2px;">' + escapeHtml(f) + '</li>';
      });
      html += '</ul>';
    }

    if (state.history.length > 0) {
      html += '<hr style="border:none;border-top:1px solid light-dark(rgba(0,0,0,0.1),rgba(255,255,255,0.1));margin:8px 0;">';
      html += '<div style="font-size:11px;color:light-dark(#888,#777);"><strong>History:</strong></div>';
      html += '<div style="font-size:11px;max-height:100px;overflow-y:auto;color:light-dark(#666,#888);margin-top:4px;">';
      state.history.slice(-5).forEach(function(h) {
        html += '<div style="margin-bottom:2px;">• ' + escapeHtml(h) + '</div>';
      });
      html += '</div>';
    }

    panel.innerHTML = html;

    const closeBtn = document.getElementById(PANEL_ID + '_close');
    if (closeBtn) {
      closeBtn.onclick = function() { togglePanel(false); };
    }
  }

  function escapeHtml(str) {
    var d = document.createElement('div');
    d.textContent = str;
    return d.innerHTML;
  }

  function togglePanel(show) {
    const state = ensureState();
    const panel = getOrCreatePanel();
    if (typeof show === 'boolean') {
      state.panelVisible = show;
    } else {
      state.panelVisible = !state.panelVisible;
    }
    panel.style.display = state.panelVisible ? 'block' : 'none';
    if (state.panelVisible) renderPanel();
  }

  function processCommand(text) {
    const state = ensureState();
    const lower = (text || '').toLowerCase().trim();

    if (lower === '/panel') {
      togglePanel();
      return;
    }
    if (lower === '/panel open') {
      togglePanel(true);
      return;
    }
    if (lower === '/panel close') {
      togglePanel(false);
      return;
    }

    if (lower.startsWith('/project ')) {
      const name = text.trim().substring(9).trim();
      if (name) {
        state.projectName = name;
        state.currentStep = 'naming';
        state.history.push('Named project: ' + name);
      }
    } else if (lower.startsWith('/type ')) {
      const ptype = text.trim().substring(6).trim();
      if (ptype) {
        state.projectType = ptype;
        state.currentStep = 'typing';
        state.history.push('Set type: ' + ptype);
      }
    } else if (lower.startsWith('/feature ')) {
      const feat = text.trim().substring(9).trim();
      if (feat && state.features.length < 20) {
        state.features.push(feat);
        state.currentStep = 'features';
        state.history.push('Added feature: ' + feat);
      }
    } else if (lower === '/review') {
      state.currentStep = 'review';
      state.history.push('Entered review step');
    } else if (lower === '/confirm') {
      state.currentStep = 'complete';
      state.history.push('Project confirmed');
    } else if (lower === '/reset') {
      state.projectName = '';
      state.projectType = '';
      state.features = [];
      state.currentStep = 'idle';
      state.history.push('Project reset');
    }

    if (state.panelVisible) renderPanel();
  }

  oc.thread.on('MessageAdded', function() {
    try {
      const msgs = oc.thread.messages;
      if (!msgs || msgs.length === 0) return;
      const last = msgs[msgs.length - 1];
      if (last.author !== 'user') return;
      const text = (last.content || '').trim();
      if (text.startsWith('/')) processCommand(text);
    } catch (e) {
      console.warn('[UIBuilderBot] MessageAdded handler error:', e);
    }
  });

  togglePanel(true);
  renderPanel();
})();
